protected SalesOrderCopyingContract createContract(SalesPurchCopy _salesPurchCopy)
{
    SalesOrderCopyingContract contract = next createContract(_salesPurchCopy);

    contract.parmCopyHeaderTextBlock(CopyTextblock_Header.value());
    contract.parmCopyLineTextBlock(CopyTextblock_Line.value());

    return contract;
}

void  init()
{
    CustFormletterParameters param = CustFormletterParameters::find();

    next init();

    CopyTextblock_Header.value(param.FWFTextBlockOrderCopyingHeader);
    CopyTextblock_Line.value(param.FWFTextBlockOrderCopyingLine);
}
